INSERT INTO `v1_a129c493332e865ab5ae16532c450682ad64eb9cdd24d9675a7f71fb3d2cc069` VALUES (1, 24, 0.0, "リン", 0.0, "2030/12/17 14:59:59", 0, 24001, 10040, 102601, "2020/04/30 12:00:00", 0.0, "あたしだって\nやるときはやるよ！", 1);
INSERT INTO `v1_a129c493332e865ab5ae16532c450682ad64eb9cdd24d9675a7f71fb3d2cc069` VALUES (1, 24, 0.0, "リン", 0.0, "2030/12/17 14:59:59", 1, 24002, 10040, 102601, "2020/04/30 12:00:00", 0.0, "ふぅ…\nこれであたしの仕事は\n終わりだね", 1);
INSERT INTO `v1_a129c493332e865ab5ae16532c450682ad64eb9cdd24d9675a7f71fb3d2cc069` VALUES (1, 24, 0.0, "リン", 0.0, "2030/12/17 14:59:59", 2, 24003, 10040, 102601, "2020/04/30 12:00:00", 0.0, "終わった終わった\n一人でもなんとか\nなるもんだね", 1);
INSERT INTO `v1_a129c493332e865ab5ae16532c450682ad64eb9cdd24d9675a7f71fb3d2cc069` VALUES (2, 24, 0.0, "リン", 0.0, "2030/12/17 14:59:59", 3, 24004, 10040, 102601, "2020/04/30 12:00:00", 0.0, "やったね！\nこれでようやく\nサボれるよ…", 2);
INSERT INTO `v1_a129c493332e865ab5ae16532c450682ad64eb9cdd24d9675a7f71fb3d2cc069` VALUES (1, 24, 0.0, "リン", 0.0, "2030/12/17 14:59:59", 4, 24005, 10040, 102601, "2020/04/30 12:00:00", 0.0, "チーズが欲しいなら\nきちんと働いて\n買いに来なよ", 1);
INSERT INTO `v1_a129c493332e865ab5ae16532c450682ad64eb9cdd24d9675a7f71fb3d2cc069` VALUES (2, 24, 0.0, "リン", 0.0, "2030/12/17 14:59:59", 5, 24006, 10040, 102601, "2020/04/30 12:00:00", 0.0, "あたしを敵に回した\n恐ろしさ\n思い知ったか！", 2);
INSERT INTO `v1_a129c493332e865ab5ae16532c450682ad64eb9cdd24d9675a7f71fb3d2cc069` VALUES (2, 24, 0.0, "リン", 0.0, "2030/12/17 14:59:59", 6, 24007, 10040, 102601, "2020/04/30 12:00:00", 0.0, "あたしも意外と\nやるもんでしょ？", 2);
INSERT INTO `v1_a129c493332e865ab5ae16532c450682ad64eb9cdd24d9675a7f71fb3d2cc069` VALUES (4, 24, 0.0, "リン", 0.0, "2030/12/17 14:59:59", 7, 24008, 10040, 102601, "2020/04/30 12:00:00", 0.0, "疲れた…\nねずみの逃げ足\n速すぎるよ…", 4);
INSERT INTO `v1_a129c493332e865ab5ae16532c450682ad64eb9cdd24d9675a7f71fb3d2cc069` VALUES (4, 24, 0.0, "リン", 0.0, "2030/12/17 14:59:59", 8, 24009, 10040, 102601, "2020/04/30 12:00:00", 0.0, "このままじゃ\nまっひ～に\n叱られちゃうよ", 4);
INSERT INTO `v1_a129c493332e865ab5ae16532c450682ad64eb9cdd24d9675a7f71fb3d2cc069` VALUES (4, 24, 0.0, "リン", 0.0, "2030/12/17 14:59:59", 9, 24010, 10040, 102601, "2020/04/30 12:00:00", 0.0, "まじめに\nやったんだけどな…\n悔しいな～", 4);
INSERT INTO `v1_a129c493332e865ab5ae16532c450682ad64eb9cdd24d9675a7f71fb3d2cc069` VALUES (4, 24, 0.0, "リン", 0.0, "2030/12/17 14:59:59", 10, 24011, 10040, 102601, "2020/04/30 12:00:00", 0.0, "やられた…\nねずみって意外と\nてごわいね", 4);
INSERT INTO `v1_a129c493332e865ab5ae16532c450682ad64eb9cdd24d9675a7f71fb3d2cc069` VALUES (4, 24, 0.0, "リン", 0.0, "2030/12/17 14:59:59", 11, 24012, 10040, 102601, "2020/04/30 12:00:00", 0.0, "おのれ～\nあたしのチーズを\n盗みやがって～！", 4);
INSERT INTO `v1_a129c493332e865ab5ae16532c450682ad64eb9cdd24d9675a7f71fb3d2cc069` VALUES (1, 24, 1.81, "リン", 0.0, "2030/12/17 14:59:59", 12, 24013, 10040, 102601, "2020/04/30 12:00:00", 0.0, "疲れた…\nけど、次こそは\n守り抜くよ…", 4);
